        while (T-- > 0) {
            int N = sc.nextInt();
            double L = sc.nextDouble();
            double R = sc.nextDouble();
            double max_height = 1001;
            for (int i = 0; i < N; i++) {
                double Xi = sc.nextDouble();
                double Yi = sc.nextDouble();
                double Zi = sc.nextDouble();
                double angle = Zi * Math.PI / 180;
                double b = 2 * Yi / Math.tan(angle);
                double x1 = Xi - b / 2;
                double x2 = Xi + b / 2;
                if (x1 <= L && x2 >= R) {
                    max_height = Math.min(max_height, Yi);
                } else if (x1 <= L && x2 <= R) {
                    double h1 = Yi - (Yi / b) * (x2 - Xi);
                    double h2 = Yi - (Yi / b) * (Xi - x1);
                    max_height = Math.min(max_height, Math.min(h1, h2));
                } else if (x1 >= L && x2 <= R) {
                    double h1 = Yi - (Yi / b) * (Xi - x1);
                    double h2 = Yi - (Yi / b) * (x2 - Xi);
